targets.expr:
clamp_min(
  (
    sum(temporal_request_total{operation="StartWorkflowExecution", namespace=~"$namespace"}) or vector(0)
  ) - (
    sum(temporal_workflow_completed_total{namespace=~"$namespace"}) or vector(0)
  ) - (
    sum(temporal_workflow_failed_total{namespace=~"$namespace"}) or vector(0)
  ) - (
    sum(temporal_workflow_cancelled_total{namespace=~"$namespace"}) or vector(0)
  ) - (
    sum(temporal_workflow_continue_as_new_total{namespace=~"$namespace"}) or vector(0)
  ),
  0
)
